Here's the complete setup:

**Program.cs**
```csharp
using OpenTelemetry.Metrics;
using OpenTelemetry.Resources;
using OpenTelemetry.Trace;

var builder = WebApplication.CreateBuilder(args);

var serviceName = "OrderApi";

builder.Services.AddOpenTelemetry()
    .ConfigureResource(r => r.AddService(serviceName))
    .WithTracing(t => t
        .AddAspNetCoreInstrumentation()
        .AddHttpClientInstrumentation()
        .AddSource(OrderService.ActivitySourceName)
        .AddOtlpExporter(o =>
        {
            o.Endpoint = new Uri(builder.Configuration["Otel:Endpoint"] ?? "http://localhost:4317");
        }))
    .WithMetrics(m => m
        .AddAspNetCoreInstrumentation()
        .AddMeter(OrderService.MeterName)
        .AddOtlpExporter(o =>
        {
            o.Endpoint = new Uri(builder.Configuration["Otel:Endpoint"] ?? "http://localhost:4317");
        }));

builder.Services.AddSingleton<OrderService>();
builder.Services.AddControllers();

var app = builder.Build();
app.MapControllers();
app.Run();
```

**OrderService.cs**
```csharp
using System.Diagnostics;
using System.Diagnostics.Metrics;

public class OrderService
{
    public const string ActivitySourceName = "OrderApi.OrderService";
    public const string MeterName = "OrderApi.OrderService";

    private static readonly ActivitySource ActivitySource = new(ActivitySourceName);
    private static readonly Meter Meter = new(MeterName);
    private static readonly Counter<long> OrdersProcessed = Meter.CreateCounter<long>(
        "orders.processed",
        unit: "{order}",
        description: "Number of orders processed");

    public async Task<bool> ProcessOrder(Order order)
    {
        using var activity = ActivitySource.StartActivity("ProcessOrder", ActivityKind.Internal);
        activity?.SetTag("order.id", order.Id);
        activity?.SetTag("order.total", order.Total);

        try
        {
            // Your processing logic here
            await Task.Delay(50); // simulate work

            activity?.SetStatus(ActivityStatusCode.Ok);
            OrdersProcessed.Add(1,
                new KeyValuePair<string, object?>("order.status", "success"));

            return true;
        }
        catch (Exception ex)
        {
            activity?.SetStatus(ActivityStatusCode.Error, ex.Message);
            activity?.RecordException(ex);
            OrdersProcessed.Add(1,
                new KeyValuePair<string, object?>("order.status", "failure"));
            throw;
        }
    }
}

public record Order(string Id, decimal Total);
```

**Required packages:**
```bash
dotnet add package OpenTelemetry.Extensions.Hosting
dotnet add package OpenTelemetry.Instrumentation.AspNetCore
dotnet add package OpenTelemetry.Instrumentation.Http
dotnet add package OpenTelemetry.Exporter.OpenTelemetryProtocol
```

**Key points:**

- `ActivitySource` is .NET's API for creating spans — `AddSource()` registers it with the OTel SDK.
- `Meter`/`Counter<T>` use `System.Diagnostics.Metrics` — `AddMeter()` registers collection.
- The OTLP exporter defaults to `localhost:4317` (gRPC). Override via config: `"Otel:Endpoint"`.
- Tags on the activity become span attributes visible in Jaeger/Grafana/etc.
- The counter is dimensioned by `order.status` so you can split success/failure in dashboards.
